const datos = $('Preparar Datos').first().json || {};
const menuRows = $input.all().map(i => i.json || {});

function normalize(v) {
  return String(v || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function tokenize(v) {
  return normalize(v)
    .split(' ')
    .map(x => x.trim())
    .filter(Boolean)
    .filter(x => !['una','uno','un','de','del','con','y','la','el','los','las','para','al','a','por','favor'].includes(x));
}

function uniq(arr) {
  return [...new Set(arr.filter(Boolean))];
}

function toNumber(v, d = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : d;
}

function dice(a, b) {
  a = normalize(a);
  b = normalize(b);
  if (!a || !b) return 0;
  if (a === b) return 1;
  const bigrams = s => {
    const out = [];
    for (let i = 0; i < s.length - 1; i++) out.push(s.slice(i, i + 2));
    return out;
  };
  const ab = bigrams(a);
  const bb = bigrams(b);
  if (!ab.length || !bb.length) return 0;
  const counts = new Map();
  for (const x of ab) counts.set(x, (counts.get(x) || 0) + 1);
  let hits = 0;
  for (const x of bb) {
    const c = counts.get(x) || 0;
    if (c > 0) {
      hits += 1;
      counts.set(x, c - 1);
    }
  }
  return (2 * hits) / (ab.length + bb.length);
}

function normalizeRequest(v) {
  return normalize(v)
    .replace(/\b4 quesos\b/g, 'cuatro quesos')
    .replace(/\bpeperoni\b/g, 'pepperoni')
    .replace(/\bcocacola\b/g, 'coca cola')
    .replace(/\bbbq pollo\b/g, 'barbacoa pollo')
    .replace(/\bbbq\b/g, 'barbacoa')
    .replace(/\bburger\b/g, 'hamburguesa')
    .replace(/\bespagueti\b/g, 'espaguetis')
    .replace(/\bspaghetti\b/g, 'espaguetis')
    .replace(/\bbolonesa\b/g, 'bolognesa')
    .replace(/\bclasica\b/g, 'clasica')
    .replace(/\s+/g, ' ')
    .trim();
}

function detectVariant(req) {
  const t = normalizeRequest(req);
  const variants = [
    'unica','única','personal','mediana','familiar','estandar','estándar',
    'lata','lata 330 ml','330 ml','botella','1 5 l','1.5 l','500 ml','sin gas','con gas'
  ];
  const found = variants.find(v => normalize(v) && t.includes(normalize(v)));
  return found ? normalize(found) : null;
}

function baseProductName(row) {
  const raw = String(row.producto || row.nombre || '').trim();
  const fromNombre = String(row.nombre || '').split(' - ')[0].trim();
  return fromNombre || raw;
}

function rowVariant(row) {
  return normalize(row.variante || '');
}

function rowBase(row) {
  return normalize(baseProductName(row));
}

function buildRowText(row) {
  return uniq([
    row.nombre,
    row.producto,
    baseProductName(row),
    row.descripcion,
    row.tags,
    row.categoria,
    row.variante,
    row.producto_display,
    row.extras_disponibles
  ]).join(' ');
}

function canonicalChoice(req, rowText) {
  const options = [
    'carbonara','bolognesa','frutti di mari','maremonti','napolitana',
    'colombiana','manzana','uva','sin gas','con gas','coca cola','pepsi',
    'fanta','sprite','ajillo','gambas','bbq bacon','barbacoa','clasica','pollo'
  ];
  const rn = normalizeRequest(req);
  const rt = normalizeRequest(rowText);
  return options.find(opt => rn.includes(opt) && rt.includes(opt)) || null;
}

function prettyChoice(choice) {
  const map = {
    'carbonara': 'Carbonara',
    'bolognesa': 'Boloñesa',
    'frutti di mari': 'Frutti di mari',
    'maremonti': 'Maremonti',
    'napolitana': 'Napolitana',
    'colombiana': 'Colombiana',
    'manzana': 'Manzana',
    'uva': 'Uva',
    'sin gas': 'sin gas',
    'con gas': 'con gas',
    'coca cola': 'Coca-Cola',
    'pepsi': 'Pepsi',
    'fanta': 'Fanta',
    'sprite': 'Sprite',
    'ajillo': 'a ajillo con gambas',
    'bbq bacon': 'BBQ Bacon',
    'barbacoa': 'Barbacoa',
    'clasica': 'Clásica',
    'pollo': 'Pollo'
  };
  return map[choice] || choice;
}

function buildDisplayName(row, req) {
  const baseNombre = String(row.nombre || row.producto || '').trim();
  const rowText = buildRowText(row);
  const choice = canonicalChoice(req, rowText);
  const variante = row.variante ? ` - ${row.variante}` : '';
  const prodNorm = normalize(row.producto || '');
  const baseNorm = normalize(baseNombre);

  if ((prodNorm.includes('salsa a elegir') || baseNorm.includes('salsa a elegir')) && choice) {
    return `Espaguetis ${prettyChoice(choice)}${variante}`;
  }
  if (baseNorm.includes('postobon') && choice) {
    return `Postobon ${prettyChoice(choice)}${variante}`;
  }
  return baseNombre;
}

function preferredVariantScore(row) {
  const v = normalize(row.variante || '');
  const base = normalize(baseProductName(row));
  let score = 0;
  if (!v || v === 'unica' || v === 'estandar') score += 40;
  if (v.includes('500 ml')) score += 30;
  if (v.includes('lata')) score += 20;
  if (v.includes('personal')) score += 25;
  if (base.includes('coca cola') || base.includes('pepsi') || base.includes('sprite') || base.includes('fanta')) {
    if (v.includes('lata')) score += 20;
  }
  return score;
}

function parseExtras(raw) {
  const text = String(raw || '').trim();
  if (!text) return [];
  const chunks = text.split(/\),\s*/).map((part, idx, arr) => {
    const p = part.trim();
    if (!p) return '';
    if (p.includes('(') && !p.endsWith(')')) return p + ')';
    return p;
  }).filter(Boolean);
  return chunks.map(chunk => {
    const match = chunk.match(/^(.*?)\s*\((\d+[\.,]\d+)€\)$/i);
    if (match) {
      return {
        nombre: match[1].trim(),
        precio: Number(String(match[2]).replace(',', '.'))
      };
    }
    return { nombre: chunk.trim(), precio: 0 };
  });
}

function extractRequestedExtras(reqItem, row) {
  const reqNorm = normalizeRequest(reqItem?.nombre || '');
  const extras = parseExtras(row.extras_disponibles);
  return extras.filter(extra => {
    const extraNorm = normalizeRequest(extra.nombre);
    return extraNorm && reqNorm.includes(extraNorm);
  });
}

function formatExtraList(extras) {
  return extras.map(x => x.precio > 0 ? `${x.nombre} (${String(x.precio.toFixed(2)).replace('.', ',')}€)` : x.nombre).join(', ');
}

function hasMeaningfulVariants(rows) {
  const variants = uniq(rows.map(r => String(r.variante || '').trim()).filter(Boolean));
  const meaningful = variants.filter(v => !['unica','única','estándar','estandar'].includes(normalize(v)));
  return { all: variants, meaningful };
}

function chooseBestRow(rows, reqItem) {
  if (!rows.length) return null;
  const wantedVariant = detectVariant(reqItem.nombre || '');
  if (wantedVariant) {
    const byVariant = rows.filter(r => rowVariant(r).includes(wantedVariant));
    if (byVariant.length) {
      return byVariant
        .slice()
        .sort((a, b) => (b.__score + preferredVariantScore(b)) - (a.__score + preferredVariantScore(a)))[0];
    }
  }
  return rows
    .slice()
    .sort((a, b) =>
      (b.__score + preferredVariantScore(b) - toNumber(b.precio, 0) * 0.01) -
      (a.__score + preferredVariantScore(a) - toNumber(a.precio, 0) * 0.01)
    )[0];
}

function scoreCandidate(reqItem, row) {
  const req = String(reqItem?.nombre || '');
  const reqNorm = normalizeRequest(req);
  const rowName = normalizeRequest(row.nombre || '');
  const rowProd = normalizeRequest(row.producto || '');
  const rowBaseName = normalizeRequest(baseProductName(row));
  const rowVar = normalizeRequest(row.variante || '');
  const rowDesc = normalizeRequest(row.descripcion || '');
  const rowTags = normalizeRequest(row.tags || '');
  const rowCat = normalizeRequest(row.categoria || '');
  const rowText = uniq([rowName, rowProd, rowBaseName, rowVar, rowDesc, rowTags, rowCat]).join(' ');
  const reqTokens = uniq(tokenize(reqNorm));
  const rowTokens = uniq(tokenize(rowText));

  let score = 0;
  if (!row.disponible) score -= 300;
  if (reqNorm === rowName || reqNorm === rowProd || reqNorm === rowBaseName) score += 180;
  if (rowName.includes(reqNorm) || rowProd.includes(reqNorm) || rowBaseName.includes(reqNorm)) score += 80;
  if (reqNorm.includes(rowName) || reqNorm.includes(rowProd) || reqNorm.includes(rowBaseName)) score += 55;

  const overlap = reqTokens.filter(t => rowTokens.includes(t)).length;
  score += overlap * 16;

  score += Math.round(dice(reqNorm, rowBaseName) * 60);
  score += Math.round(dice(reqNorm, rowName) * 45);

  if (reqNorm.includes('pizza') && row.is_pizza) score += 14;
  if (reqNorm.includes('hamburguesa') && rowCat.includes('hamburguesa')) score += 14;
  if ((reqNorm.includes('bebida') || reqNorm.includes('refresco')) && rowCat.includes('bebida')) score += 10;
  if ((reqNorm.includes('pasta') || reqNorm.includes('espaguetis')) && rowCat.includes('pasta')) score += 10;

  const wantedVariant = detectVariant(req);
  if (wantedVariant) {
    if (rowVar.includes(wantedVariant)) score += 35;
    else score -= 15;
  }

  const choice = canonicalChoice(req, rowText);
  if (choice) score += 24;

  if (reqNorm.includes('pollo')) {
    if (rowText.includes('pollo')) score += 55;
    else score -= 45;
  }
  if (!reqNorm.includes('pollo') && reqNorm.includes('barbacoa') && rowText.includes('barbacoa pollo')) {
    score -= 18;
  }

  if (reqNorm.includes('lanzarote') && rowText.includes('lanzarote')) score += 50;
  if (reqNorm.includes('barbacoa') && rowText.includes('barbacoa')) score += 40;
  if (reqNorm.includes('vegana') && rowText.includes('vegana')) score += 40;
  if (reqNorm.includes('clasica') && rowText.includes('clasica')) score += 40;
  if (reqNorm.includes('carbonara') && rowText.includes('carbonara')) score += 40;
  if (reqNorm.includes('coca cola') && rowText.includes('coca cola')) score += 40;
  if (reqNorm.includes('postobon') && rowText.includes('postobon')) score += 35;

  return { score, row };
}

function buildProblem(nombre, problema, mensaje, opciones = [], obligatorio = true) {
  return { nombre, problema, mensaje, opciones, obligatorio };
}

function categoryOptions(reqItem) {
  const t = normalizeRequest(reqItem?.nombre);
  if (!t) return null;
  if (['pizza','pizzas'].includes(t)) return { categoria: 'Pizzas', texto: 'Qué pizza quieres? Puedo ofrecerte Lanzarote, Barbacoa, Barbacoa Pollo, Cuatro Quesos, Margarita, Pepperoni o Vegana Suprema.' };
  if (['hamburguesa','hamburguesas'].includes(t)) return { categoria: 'Hamburguesas', texto: 'Qué hamburguesa quieres? Puedo ofrecerte BBQ Bacon, Clásica, Doble Veggie o Pollo Crispy.' };
  if (['bebida','bebidas','refresco','refrescos'].includes(t)) return { categoria: 'Bebidas', texto: 'Qué bebida quieres? Puedo ofrecerte Agua Mineral, Coca-Cola, Pepsi, Fanta, Sprite, Postobon o Cerveza Tropical.' };
  if (['pasta','pastas','espaguetis'].includes(t)) return { categoria: 'Pastas', texto: 'Qué pasta quieres? Puedes pedir Carbonara, Boloñesa, Napolitana o Espaguetis a ajillo con gambas.' };
  return null;
}

function dedupeValidated(items) {
  const map = new Map();
  for (const item of items) {
    const key = normalize(item.nombre + '|' + (item.notas || ''));
    if (!map.has(key)) {
      map.set(key, { ...item });
    } else {
      const cur = map.get(key);
      cur.cantidad += toNumber(item.cantidad, 1);
      cur.subtotal = Number((cur.cantidad * toNumber(cur.precio_unitario, 0)).toFixed(2));
      map.set(key, cur);
    }
  }
  return [...map.values()];
}

const result = {
  pedido_id: datos.pedido_id || null,
  pedido_numero: datos.pedido_numero || null,
  pedido_codigo: datos.pedido_codigo || null,
  session_id: datos.session_id || null,
  telefono: datos.telefono || null,
  items_actuales: Array.isArray(datos.items_actuales) ? datos.items_actuales : [],
  subtotal_actual: toNumber(datos.subtotal_actual, 0),
  total_actual: toNumber(datos.total_actual, 0),
  accion: datos.accion || 'consultar',
  usuario_id: datos.usuario_id || null,
  forzar_pedido_nuevo: datos.forzar_pedido_nuevo || false,
  items_nuevos: Array.isArray(datos.items_nuevos) ? datos.items_nuevos : [],
  items_validados: [],
  items_problematicos: [],
  necesita_aclaracion: false,
  pregunta_aclaracion: null,
  puede_continuar: true,
  tiene_pendientes: false
};

if (String(result.accion).toLowerCase() === 'consultar') {
  return [{ json: result }];
}

if (!result.items_nuevos.length) {
  result.puede_continuar = false;
  result.tiene_pendientes = true;
  result.items_problematicos.push(buildProblem('pedido', 'sin_items', 'No encontré productos para procesar en tu mensaje.'));
  return [{ json: result }];
}

for (const reqItem of result.items_nuevos) {
  const reqName = String(reqItem?.nombre || '').trim();
  const reqNorm = normalizeRequest(reqName);
  const qty = Math.max(1, toNumber(reqItem?.cantidad, 1));
  if (!reqName) continue;

  const catAmb = categoryOptions(reqItem);
  if (catAmb) {
    result.necesita_aclaracion = true;
    result.tiene_pendientes = true;
    result.items_problematicos.push(buildProblem(reqName, 'categoria_ambigua', catAmb.texto));
    continue;
  }

  const scored = menuRows
    .map(r => scoreCandidate(reqItem, r))
    .filter(x => x.score > 18)
    .sort((a, b) => b.score - a.score);

  if (!scored.length) {
    result.tiene_pendientes = true;
    result.items_problematicos.push(buildProblem(reqName, 'no_existe', `No encontré "${reqName}" en el menú.`));
    continue;
  }

  const groups = new Map();
  for (const s of scored) {
    const key = rowBase(s.row);
    if (!groups.has(key)) groups.set(key, []);
    s.row.__score = s.score;
    groups.get(key).push(s.row);
  }

  let grouped = [...groups.entries()]
    .map(([base, rows]) => ({
      base,
      rows,
      bestScore: Math.max(...rows.map(r => toNumber(r.__score, 0))),
      labels: uniq(rows.map(r => baseProductName(r)))
    }))
    .sort((a, b) => b.bestScore - a.bestScore);

  if (!grouped.length) {
    result.tiene_pendientes = true;
    result.items_problematicos.push(buildProblem(reqName, 'no_existe', `No encontré "${reqName}" en el menú.`));
    continue;
  }

  const exactGroup = grouped.find(g => reqNorm === g.base || reqNorm.includes(g.base) || g.base.includes(reqNorm));
  if (exactGroup) {
    grouped = [exactGroup, ...grouped.filter(g => g.base !== exactGroup.base)];
  }

  const bestGroup = grouped[0];
  const secondGroup = grouped[1] || null;

  if (!bestGroup || bestGroup.bestScore < 25) {
    result.tiene_pendientes = true;
    result.items_problematicos.push(buildProblem(reqName, 'no_existe', `No encontré "${reqName}" en el menú.`));
    continue;
  }

  if (!exactGroup && secondGroup && bestGroup.bestScore - secondGroup.bestScore <= 8 && bestGroup.base !== secondGroup.base) {
    const opciones = uniq([baseProductName(bestGroup.rows[0]), baseProductName(secondGroup.rows[0])]).slice(0, 4);
    result.necesita_aclaracion = true;
    result.tiene_pendientes = true;
    result.items_problematicos.push(buildProblem(
      reqName,
      'ambiguo',
      `Quiero confirmar "${reqName}". ¿Te refieres a ${opciones.join(' o ')}?`,
      opciones
    ));
    continue;
  }

  const variantsInfo = hasMeaningfulVariants(bestGroup.rows);
  const wantedVariant = detectVariant(reqName);
  if (!wantedVariant && variantsInfo.meaningful.length > 1) {
    const producto = baseProductName(bestGroup.rows[0]);
    const opciones = variantsInfo.meaningful;
    result.necesita_aclaracion = true;
    result.tiene_pendientes = true;
    result.items_problematicos.push(buildProblem(
      reqName,
      'variante_requerida',
      `Para ${producto} necesito el tamaño o variante. Opciones: ${opciones.join(', ')}.`,
      opciones
    ));
    continue;
  }

  const bestRow = chooseBestRow(bestGroup.rows, reqItem);
  if (!bestRow) {
    result.tiene_pendientes = true;
    result.items_problematicos.push(buildProblem(reqName, 'no_existe', `No encontré "${reqName}" en el menú.`));
    continue;
  }

  const nombreFinal = buildDisplayName(bestRow, reqName);
  const precioBase = toNumber(bestRow.precio, 0);

  // ── Extras con extra_id desde extras_json (M-12) ──────────────
  // Buscar extras mencionados en el nombre del ítem O en reqItem.notas
  const searchText = normalizeRequest(
    (reqItem?.nombre || '') + ' ' + (reqItem?.notas || '')
  );
  // extras_json puede llegar como array (n8n parsea JSONB) o como string en algunos entornos
  let _rawExtrasJson = bestRow.extras_json;
  if (typeof _rawExtrasJson === 'string' && _rawExtrasJson.trim()) {
    try { _rawExtrasJson = JSON.parse(_rawExtrasJson); } catch(e) { _rawExtrasJson = []; }
  }
  const availableExtrasJson = Array.isArray(_rawExtrasJson) ? _rawExtrasJson : [];
  const matchedExtras = availableExtrasJson.filter(ex => {
    const exNorm = normalizeRequest(ex.name);
    return exNorm && searchText.includes(exNorm);
  });

  // Extras como array estructurado con extra_id
  const extrasArray = matchedExtras.map(ex => ({
    extra_id:   Number(ex.extra_id),
    name:       String(ex.name),
    quantity:   1,
    unit_price: Number(ex.price || 0)
  }));
  const extrasTotal = extrasArray.reduce((acc, ex) => acc + ex.unit_price * ex.quantity, 0);
  const precio = Number((precioBase + extrasTotal).toFixed(2));

  // ── Notas: solo preferencias de cocina que NO sean extras del menú ─
  // Si reqItem.notas coincide completamente con un extra detectado, no lo repetimos en notas
  const notasTexto = reqItem.notas && String(reqItem.notas).trim()
    ? String(reqItem.notas).trim()
    : null;
  const notasEsExtra = notasTexto && matchedExtras.some(ex =>
    normalizeRequest(notasTexto).includes(normalizeRequest(ex.name))
  );
  const notasItem = notasEsExtra ? null : notasTexto;

  result.items_validados.push({
    nombre:          nombreFinal,
    cantidad:        qty,
    precio_unitario: precio,
    subtotal:        Number((qty * precio).toFixed(2)),
    notas:           notasItem,
    extras:          extrasArray
  });

  const availableExtras = availableExtrasJson.length
    ? availableExtrasJson.map(ex => ({ nombre: ex.name, precio: Number(ex.price || 0) }))
    : parseExtras(bestRow.extras_disponibles);  // fallback texto si extras_json vacío
  if (availableExtras.length && matchedExtras.length === 0 && String(result.accion || '').toLowerCase() === 'agregar') {
    result.tiene_pendientes = true;
    result.items_problematicos.push(buildProblem(
      nombreFinal,
      'extras_opcionales',
      `Para ${nombreFinal} puedes agregar extras: ${formatExtraList(availableExtras)}. ¿Quieres añadir alguno?`,
      availableExtras.map(x => x.nombre),
      false
    ));
  }
}

result.items_validados = dedupeValidated(result.items_validados);

const blockingProblems = result.items_problematicos.filter(x => x.obligatorio !== false);
if (!result.items_validados.length && (result.necesita_aclaracion || blockingProblems.length > 0)) {
  result.puede_continuar = false;
}

if (!result.items_validados.length && !result.items_problematicos.length) {
  result.puede_continuar = false;
  result.tiene_pendientes = true;
  result.items_problematicos.push(buildProblem('pedido', 'sin_coincidencias', 'No pude validar los productos que me pediste.'));
}

if (result.items_problematicos.length > 0 || result.necesita_aclaracion) {
  result.tiene_pendientes = true;
}

if (result.items_validados.length > 0) {
  result.puede_continuar = true;
}

if (result.necesita_aclaracion && !result.pregunta_aclaracion) {
  const firstBlocking = result.items_problematicos.find(x => x.obligatorio !== false);
  result.pregunta_aclaracion = firstBlocking?.mensaje || null;
}

return [{ json: result }];

const input = $input.first().json || {};

function normalize(v) {
  return String(v || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function toNumber(v, d = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : d;
}

function recalc(item) {
  const cantidad = Math.max(0, toNumber(item?.cantidad, 1));
  const precio = toNumber(item?.precio_unitario, 0);
  return {
    notas:           item?.notas ?? null,
    nombre:          String(item?.nombre || '').trim(),
    cantidad,
    subtotal:        Number((cantidad * precio).toFixed(2)),
    precio_unitario: precio,
    extras:          Array.isArray(item?.extras) ? item.extras : []
  };
}

function mergeExtras(existing, incoming) {
  const base = Array.isArray(existing) ? existing : [];
  const inc  = Array.isArray(incoming)  ? incoming  : [];
  if (!inc.length) return base;
  const map = new Map(base.map(e => [e.extra_id, { ...e }]));
  for (const ex of inc) { map.set(ex.extra_id, { ...ex }); }
  return [...map.values()];
}

const accion = String(input.accion || 'consultar').toLowerCase().trim();
const itemsActuales = Array.isArray(input.items_actuales) ? input.items_actuales.map(recalc) : [];
const itemsValidados = Array.isArray(input.items_validados) ? input.items_validados.map(recalc) : [];
const itemsProblematicos = Array.isArray(input.items_problematicos) ? input.items_problematicos : [];
const tienePendientes = Boolean(input.tiene_pendientes || input.necesita_aclaracion || itemsProblematicos.length > 0);

function findIndexByName(arr, nombre) {
  const target = normalize(nombre);
  return arr.findIndex(x => normalize(x?.nombre) === target);
}

if (accion === 'consultar') {
  return [{
    json: {
      success: true,
      puede_continuar: true,
      mutar_db: false,
      pedido_id: input.pedido_id || null,
      pedido_numero: input.pedido_numero || null,
      pedido_codigo: input.pedido_codigo || null,
      session_id: input.session_id || null,
      telefono: input.telefono || null,
      items_actualizados: itemsActuales,
      subtotal: toNumber(input.subtotal_actual, 0),
