      });
    } else {
      itemsActualizados.push(recalc(item));
    }
  }
} else if (accion === 'quitar') {
  for (const item of itemsValidados) {
    const idx = findIndexByName(itemsActualizados, item.nombre);
    if (idx >= 0) {
      const restante = toNumber(itemsActualizados[idx].cantidad, 0) - Math.max(1, toNumber(item.cantidad, 1));
      if (restante <= 0) {
        itemsActualizados.splice(idx, 1);
      } else {
        itemsActualizados[idx] = recalc({
          ...itemsActualizados[idx],
          cantidad: restante
        });
      }
    }
  }
} else if (accion === 'modificar') {
  for (const item of itemsValidados) {
    const idx = findIndexByName(itemsActualizados, item.nombre);
    if (idx >= 0) {
      itemsActualizados[idx] = recalc({
        ...itemsActualizados[idx],
