function normalize(v) {
  return String(v || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function toNumber(v, d = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : d;
}

function singularCategory(cat) {
  const t = normalize(cat);
  if (t.includes('pizza')) return 'pizza';
  if (t.includes('hamburguesa')) return 'hamburguesa';
  if (t.includes('bebida') || t.includes('refresco')) return 'bebida';
  if (t.includes('pasta') || t.includes('espagueti') || t.includes('spaghetti')) return 'pasta';
  return '';
}

function extractQtyAndName(texto, qtyFallback = 1) {
  let t = String(texto || '').trim();
  if (!t) return null;

  const patrones = [
    [/^(una|un|uno)\s+/i, 1],
    [/^(dos|2)\s+/i, 2],
    [/^(tres|3)\s+/i, 3],
    [/^(cuatro|4)\s+/i, 4],
    [/^(cinco|5)\s+/i, 5],
  ];

  let qty = Math.max(1, toNumber(qtyFallback, 1));
  for (const [rx, value] of patrones) {
    if (rx.test(t)) {
      qty = value;
      t = t.replace(rx, '').trim();
      break;
    }
  }

  t = t
    .replace(/^(de|del)\s+/i, '')
    .replace(/\s+/g, ' ')
    .trim();

  if (!t) return null;
  return { nombre: t, cantidad: qty };
}

function splitCompositeItem(item) {
  const nombreOriginal = String(item?.nombre || '').trim();
  const qtyOriginal = Math.max(1, toNumber(item?.cantidad, 1));
  // Preservar notas del item original a través del split
  const notasOriginal = item?.notas && String(item.notas).trim() ? String(item.notas).trim() : null;

  if (!nombreOriginal) return [];

  const normalized = normalize(nombreOriginal);
  const rawHasManyProducts = /[,;]/.test(nombreOriginal) || /\b(y|e)\b/i.test(nombreOriginal);
  const rawPluralCategory = /\b(pizzas|hamburguesas|bebidas|refrescos|pastas)\b/i.test(nombreOriginal);

  if (!rawHasManyProducts || qtyOriginal > 1 && !rawPluralCategory) {
    return [{ nombre: nombreOriginal, cantidad: qtyOriginal, notas: notasOriginal }];
  }

  let contextCategory = singularCategory(nombreOriginal);
  let working = nombreOriginal
    .replace(/\s+/g, ' ')
    .replace(/\s+y\s+/gi, '|')
    .replace(/\s+e\s+/gi, '|')
    .replace(/,/g, '|');

  const parts = working
    .split('|')
    .map(x => x.trim())
    .filter(Boolean);

  const expanded = [];
  for (let idx = 0; idx < parts.length; idx++) {
    const part = parts[idx];
    const parsed = extractQtyAndName(part, 1);
    if (!parsed) continue;

    let nombre = parsed.nombre;
    const partNorm = normalize(nombre);

    if (!contextCategory && idx === 0) {
      contextCategory = singularCategory(nombre);
    }

    const alreadyHasCategory =
      /\bpizza\b/i.test(nombre) ||
      /\bhamburguesa\b/i.test(nombre) ||
      /\bbebida\b/i.test(nombre) ||
      /\brefresco\b/i.test(nombre) ||
      /\bpasta\b/i.test(nombre);

    if (contextCategory && !alreadyHasCategory) {
      nombre = `${contextCategory} ${nombre}`.trim();
    }

    nombre = nombre
      .replace(/\b(de la casa|del local)\b/gi, '')
      .replace(/\s+/g, ' ')
      .trim();

    expanded.push({
      nombre,
      cantidad: parsed.cantidad,
      notas: notasOriginal
    });
  }

  return expanded.length ? expanded : [{ nombre: nombreOriginal, cantidad: qtyOriginal, notas: notasOriginal }];
}

